('old-data-berta2-all-20260501-01', 'rec5vqdPwSdrFzsvs', 'MA_WATER_READING', U&'L\2019h\00F4tel est \00E9quip\00E9 des \00E9quipements sanitaires les plus r\00E9cents, incluant notamment des mousseurs et des robinets avec cran \00E9conomiseur d\2019eau \00E0 double position, qui permettent de limiter le d\00E9bit et donc la consommation. Les WC sont \00E9quip\00E9s de la m\00EAme mani\00E8re de chasse-d \2019eau \00E0 double poussoir.', 'D_Durable', U&'{"ID_D_D":"c8cde98a","Object_id":"rec5vqdPwSdrFzsvs","Type_D_D":"Gestion de l''eau","Commentaire":"L\2019h\00F4tel est \00E9quip\00E9 des \00E9quipements sanitaires les plus r\00E9cents, incluant notamment des mousseurs et des robinets avec cran \00E9conomiseur d\2019eau \00E0 double position, qui permettent de limiter le d\00E9bit et donc la consommation. Les WC sont \00E9quip\00E9s de la m\00EAme mani\00E8re de chasse-d \2019eau \00E0 double poussoir.","source_system":"berta_v2_csv_export"}', 'review_required', 'false'),
('old-data-berta2-all-20260501-01', 'rec5vqdPwSdrFzsvs', 'MA_MONTHLY_ENERGY_READING', U&'R\00E9duction de la consommation \00E9lectrique (pas de t\00E9l\00E9vision dans les chambres, \00E9clairage ext\00E9rieur avec d\00E9tecteur de pr\00E9sence)', 'D_Durable', U&'{"ID_D_D":"d53322b2","Object_id":"rec5vqdPwSdrFzsvs","Type_D_D":"Gestion de l''\00E9nergie","Commentaire":"R\00E9duction de la consommation \00E9lectrique (pas de t\00E9l\00E9vision dans les chambres, \00E9clairage ext\00E9rieur avec d\00E9tecteur de pr\00E9sence)","source_system":"berta_v2_csv_export"}', 'review_required', 'false'),
('old-data-berta2-all-20260501-01', 'rec5vqdPwSdrFzsvs', 'MA_BIODIVERSITY_AWARENESS', U&'Le v\00E9g\00E9tal fait partie int\00E9grante de la strat\00E9gie environnementale du projet du Dimitile. Le projet paysager met en valeur les esp\00E8ces end\00E9miques et la biodiversit\00E9 du site : les plus gros sujets ont d\2019ailleurs \00E9t\00E9 d\00E9plant\00E9s, mis en nourrice, puis replant\00E9s \00E0 l\2019issue des travaux.', 'D_Durable', U&'{"ID_D_D":"f80621a1","Object_id":"rec5vqdPwSdrFzsvs","Type_D_D":"Pr\00E9servation de la biodiversit\00E9","Commentaire":"Le v\00E9g\00E9tal fait partie int\00E9grante de la strat\00E9gie environnementale du projet du Dimitile. Le projet paysager met en valeur les esp\00E8ces end\00E9miques et la biodiversit\00E9 du site : les plus gros sujets ont d\2019ailleurs \00E9t\00E9 d\00E9plant\00E9s, mis en nourrice, puis replant\00E9s \00E0 l\2019issue des travaux.","source_system":"berta_v2_csv_export"}', 'review_required', 'false'),
('old-data-berta2-all-20260501-01', '022C4A9B1C', 'MA_COMMON_BINS', U&'Suppression des consommables \00E0 usage unique et l\2019\00E9limination des emballages plastiques.', 'D_Durable', U&'{"ID_D_D":"2f23e26f","Object_id":"022C4A9B1C","Type_D_D":"Gestion des d\00E9chets","Commentaire":"Suppression des consommables \00E0 usage unique et l\2019\00E9limination des emballages plastiques.","source_system":"berta_v2_csv_export"}', 'review_required', 'false'),
('old-data-berta2-all-20260501-01', '022C4A9B1C', 'MA_LOCAL_SUPPLIER_LIST', U&'Le restaurant du Dimitile souhaite promouvoir le savoir-faire et l\2019agriculture de l\2019\00EEle en privil\00E9giant les fruits et l\00E9gumes locaux et de saison. Les mara\00EEchers sont s\00E9lectionn\00E9s pour la qualit\00E9 de leurs produits et l\2019utilisation limit\00E9e de pesticides dans leurs exploitations.', 'D_Durable', U&'{"ID_D_D":"1ca44c32","Object_id":"022C4A9B1C","Type_D_D":"Produits en circuit court","Commentaire":"Le restaurant du Dimitile souhaite promouvoir le savoir-faire et l\2019agriculture de l\2019\00EEle en privil\00E9giant les fruits et l\00E9gumes locaux et de saison. Les mara\00EEchers sont s\00E9lectionn\00E9s pour la qualit\00E9 de leurs produits et l\2019utilisation limit\00E9e de pesticides dans leurs exploitations.","source_system":"berta_v2_csv_export"}', 'review_required', 'false'),
('old-data-berta2-all-20260501-01', 'rec5vqdPwSdrFzsvs', NULL, U&'Les b\00E2timents du Dimitile ont \00E9t\00E9 con\00E7u en int\00E9grant les grands principes bioclimatiques : orientation des \00E9difices, utilisation de voiles d\2019ombrages ou dimensionnement des d\00E9bords de toit pour g\00E9rer au mieux les apports solaires en les favorisant lors de la saison fra\00EEche et en s\2019en prot\00E9geant lors de la saison chaude.', 'D_Durable', U&'{"ID_D_D":"84c40691","Object_id":"rec5vqdPwSdrFzsvs","Type_D_D":"Construction bioclimatique","Commentaire":"Les b\00E2timents du Dimitile ont \00E9t\00E9 con\00E7u en int\00E9grant les grands principes bioclimatiques : orientation des \00E9difices, utilisation de voiles d\2019ombrages ou dimensionnement des d\00E9bords de toit pour g\00E9rer au mieux les apports solaires en les favorisant lors de la saison fra\00EEche et en s\2019en prot\00E9geant lors de la saison chaude.","source_system":"berta_v2_csv_export"}', 'rejected', 'false'),
('old-data-berta2-all-20260501-01', 'rec5vqdPwSdrFzsvs', NULL, U&'Formation du personnel aux pratiques \00E9coresponsables (formation obligatoire d\00E9marche \00E9co responsable dans une entreprise).', 'D_Durable', U&'{"ID_D_D":"9dc593d0","Object_id":"rec5vqdPwSdrFzsvs","Type_D_D":"Sensibilisation du personnel","Commentaire":"Formation du personnel aux pratiques \00E9coresponsables (formation obligatoire d\00E9marche \00E9co responsable dans une entreprise).","source_system":"berta_v2_csv_export"}', 'rejected', 'false'),
